def live_routes():
    """Route lines from a fresh subprocess — fully isolated from this process."""
    env = dict(os.environ, OMNIVOICE_MODEL="test", OMNIVOICE_DISABLE_FILE_LOG="1")
    proc = subprocess.run(
        [sys.executable, str(_REPO / "scripts" / "dump_api_routes.py"), "--print"],
        cwd=str(_REPO), env=env, capture_output=True, text=True, timeout=180,
    )
    assert proc.returncode == 0, f"route dump failed:\n{proc.stderr}"
    return {ln.strip() for ln in proc.stdout.splitlines() if ln.strip()}

def kg_call_spy(monkeypatch):
    """Record any HTTP call client_api attempts; fail loud if polykg is hit."""
    calls = []

    def _record(method):
        def _spy(url, **kwargs):
            calls.append((method, url))
            raise AssertionError(
                f"polykg disabled but client attempted {method.upper()} {url!r}"
            )

        return _spy

    monkeypatch.setattr(client_api.requests, "get", _record("get"))
    monkeypatch.setattr(client_api.requests, "post", _record("post"))
    return calls

