def tearDown(self):
        from cc_daemon import runner_supervisor as rs
        rs._RESTART_SPAWNER = self._restore_spawner
        with rs._handles_lock:
            for h in list(rs._handles.values()):
                t = h._restart_timer
                if t is not None:
                    try:
                        t.cancel()
                    except Exception:
                        pass
                try:
                    h.proc.kill()
                except Exception:
                    pass
            rs._handles.clear()

